import{_ as i,o as a,c as e,a2 as t}from"./chunks/framework.Crpw6aS5.js";const q=JSON.parse('{"title":"2019年巴菲特致股东信核心总结","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/2019年/核心总结.md","filePath":"01_letters/2019年/核心总结.md"}'),r={name:"01_letters/2019年/核心总结.md"};function o(h,l,u,n,d,s){return a(),e("div",null,[...l[0]||(l[0]=[t('<h1 id="_2019年巴菲特致股东信核心总结" tabindex="-1">2019年巴菲特致股东信核心总结 <a class="header-anchor" href="#_2019年巴菲特致股东信核心总结" aria-label="Permalink to &quot;2019年巴菲特致股东信核心总结&quot;">​</a></h1><h2 id="业绩表现" tabindex="-1">业绩表现 <a class="header-anchor" href="#业绩表现" aria-label="Permalink to &quot;业绩表现&quot;">​</a></h2><ul><li>GAAP净利润814亿美元，但包含537亿美元未实现投资收益</li><li>营业利润240亿美元，与2018年基本持平</li><li>每股市场价值增长11.0%，但落后于标普500的31.5%</li><li>55年来复合年化收益率20.3%，远超标普500的10.0%</li></ul><h2 id="留存收益的力量" tabindex="-1">留存收益的力量 <a class="header-anchor" href="#留存收益的力量" aria-label="Permalink to &quot;留存收益的力量&quot;">​</a></h2><ul><li>引用Edgar Lawrence Smith《普通股作为长期投资》(1924年)的核心观点</li><li>留存收益的复利效应是企业价值增长的关键</li><li>伯克希尔前十大持仓留存收益83亿美元，是股息38亿美元的2倍多</li><li>苹果留存收益25亿美元占首位</li></ul><h2 id="会计准则影响" tabindex="-1">会计准则影响 <a class="header-anchor" href="#会计准则影响" aria-label="Permalink to &quot;会计准则影响&quot;">​</a></h2><ul><li>2018年新GAAP规则要求计入未实现损益</li><li>导致2018年亏损206亿（GAAP利润40亿），2019年盈利537亿（GAAP利润814亿）</li><li>强调投资者应关注营业利润而非GAAP利润的剧烈波动</li></ul><h2 id="非保险业务表现" tabindex="-1">非保险业务表现 <a class="header-anchor" href="#非保险业务表现" aria-label="Permalink to &quot;非保险业务表现&quot;">​</a></h2><ul><li>税后净利润177亿美元，增长3%</li><li>BNSF和BHE合计贡献83亿美元</li><li>Clayton等五家贡献48亿美元</li><li>业务广泛性：从火灾损失到保险理赔的自循环案例（Lubrizol工厂火灾）</li></ul><h2 id="保险业务亮点" tabindex="-1">保险业务亮点 <a class="header-anchor" href="#保险业务亮点" aria-label="Permalink to &quot;保险业务亮点&quot;">​</a></h2><ul><li>浮存金增至1294亿美元，创历史新高</li><li>过去17年16年实现承保利润，累计275亿美元</li><li>2019年承保利润4亿美元</li><li>收购GUARD保险集团：保费从2012年增长379%至19亿美元</li></ul><h2 id="伯克希尔能源-bhe-成就" tabindex="-1">伯克希尔能源（BHE）成就 <a class="header-anchor" href="#伯克希尔能源-bhe-成就" aria-label="Permalink to &quot;伯克希尔能源（BHE）成就&quot;">​</a></h2><ul><li>爱荷华州电价20年仅上涨不到1%，承诺到2028年不涨价</li><li>竞争对手电价高出61%-70%</li><li>2021年将实现风能发电自给自足（2520万MWh vs 需求2460万MWh）</li><li>吸引高科技巨头入驻（五大客户中三个为科技公司）</li><li>20年来从未分红，留存280亿美元用于再投资</li></ul><h2 id="投资组合" tabindex="-1">投资组合 <a class="header-anchor" href="#投资组合" aria-label="Permalink to &quot;投资组合&quot;">​</a></h2><ul><li>年末市值2480亿美元</li><li>苹果成最大持仓（737亿美元），持股5.7%</li><li>美国银行333亿美元，美国运通189亿美元，可口可乐221亿美元</li><li>新增西方石油100亿美元投资（优先股+认股权证）</li><li>被投资公司平均ROE超20%</li></ul><h2 id="美国顺风-继续" tabindex="-1">&quot;美国顺风&quot;继续 <a class="header-anchor" href="#美国顺风-继续" aria-label="Permalink to &quot;&quot;美国顺风&quot;继续&quot;">​</a></h2><ul><li>1942年114.75美元投入标普500将增至60.7万美元</li><li>股票远优于债券（30年期国债仅2.5%收益）</li><li>国债增加400倍但美国企业依然创造巨大价值</li><li>警告：市场可能随时下跌50%以上</li></ul><h2 id="董事会治理" tabindex="-1">董事会治理 <a class="header-anchor" href="#董事会治理" aria-label="Permalink to &quot;董事会治理&quot;">​</a></h2><ul><li>巴菲特担任21家上市公司董事的丰富经验</li><li>批评当前独立董事制度：高薪酬（25-30万美元/年）导致独立性受损</li><li>CEO倾向选择&quot;听话&quot;的董事而非&quot;斗牛犬&quot;</li><li>强调董事应有商业头脑和所有者思维</li></ul><h2 id="接班计划" tabindex="-1">接班计划 <a class="header-anchor" href="#接班计划" aria-label="Permalink to &quot;接班计划&quot;">​</a></h2><ul><li>查理和巴菲特已进入&quot;紧急区&quot;（高龄）</li><li>伯克希尔100%为他们的离开做好准备</li><li>五大保障：优质资产组合、统一架构、财务安全、优秀管理层、忠诚董事会</li><li>巴菲特99%净资产在伯克希尔，遗嘱要求死后12-15年才能全部出售</li><li>Ajit Jain和Greg Abel将在股东大会上获得更多曝光</li></ul><h2 id="回购政策" tabindex="-1">回购政策 <a class="header-anchor" href="#回购政策" aria-label="Permalink to &quot;回购政策&quot;">​</a></h2><ul><li>2019年回购50亿美元（约1%股份）</li><li>条件：a) 价格低于内在价值 b) 完成后仍有充足现金</li><li>希望长期减少股份数量</li><li>不在任何价格支撑股价</li></ul><h2 id="纳税贡献" tabindex="-1">纳税贡献 <a class="header-anchor" href="#纳税贡献" aria-label="Permalink to &quot;纳税贡献&quot;">​</a></h2><ul><li>2019年向联邦政府缴纳所得税36亿美元</li><li>占全美企业所得税收入的1.5%</li><li>55年前伯克希尔不缴纳联邦所得税</li></ul><h2 id="股东大会" tabindex="-1">股东大会 <a class="header-anchor" href="#股东大会" aria-label="Permalink to &quot;股东大会&quot;">​</a></h2><ul><li>2020年5月2日举行</li><li>Ajit Jain和Greg Abel将更多亮相</li><li>记者提问可指定由二人回答</li></ul><h2 id="关键启示" tabindex="-1">关键启示 <a class="header-anchor" href="#关键启示" aria-label="Permalink to &quot;关键启示&quot;">​</a></h2><ul><li>关注留存收益而非股息</li><li>股票长期优于债券</li><li>公司治理需要真正的独立思考</li><li>伯克希尔文化是持久竞争优势</li></ul>',29)])])}const b=i(r,[["render",o]]);export{q as __pageData,b as default};
